function candidate(left, right, originalOnly) {
  const textOrder = (a, b) => {
    if (a === b) return 0;
    return a > b ? 1 : -1;
  };

  let result = textOrder(left.source, right.source);
  if (result !== 0) return result;

  result = left.originalLine - right.originalLine;
  if (result !== 0) return result;

  result = left.originalColumn - right.originalColumn;
  if (result !== 0 || originalOnly) return result;

  result = left.generatedColumn - right.generatedColumn;
  if (result !== 0) return result;

  result = left.generatedLine - right.generatedLine;
  if (result !== 0) return result;

  return textOrder(left.name, right.name);
}
